from math import comb
def TreeArray(nmax: int, kmax: int) -> list[list[int]]:
    if kmax <= 0 or nmax <= 0: return []
    M = []
    for i in range(kmax):
        row = []
        n = i + 1
        for j in range(i + 1):
            weight = comb(i, j) * (n ** (i - j))
            row.append(weight)
        M.append(row)
    V = [1] + [0] * (kmax - 1)
    result = [V]
    for _ in range(nmax - 1):
        V_next = []
        for i in range(kmax):
            val = sum(M[i][j] * V[j] for j in range(i + 1))
            V_next.append(val)
        V = V_next
        result.append(V)
    return result
for row in TreeArray(7, 6): print("".join(f"{num:<9}" for num in row))
